class OledDisplay {
  constructor(i2cPort, slaveAddress) {
    this.i2cPort = i2cPort;
    this.i2cSlave = null;
    this.slaveAddress = slaveAddress || OLED_CONST.address;
    this.funcQueue = new Array();
    this.sequence = null;
    this.addressingMode = OLED_CONST.pageMode;
    this.useSSD1306 = false;
    this.useSSD1315 = false;
    this.displayWidth = 128;
    this.displayHeight = 64;
    this.columnOffset = 0;
    this.comPins = null;  // null = auto (height-based default)
  }

  #initQ() {
    // COM Pins Hardware Configuration: 0x12 for >32 rows (alternative), 0x02 for ≤32 rows (sequential)
    // Can be overridden via init() options
    const comPins = (this.comPins !== null) ? this.comPins : ((this.displayHeight > 32) ? 0x12 : 0x02);
    if (this.useSSD1315) {
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.displayOffCmd);      // 0xae
      this.#registerQueue(OLED_CONST.commandMode, 0xd5);  // Set Display Clock Divide Ratio
      this.#registerQueue(OLED_CONST.commandMode, 0x80);
      this.#registerQueue(OLED_CONST.commandMode, 0xa8);  // Set Multiplex Ratio
      this.#registerQueue(OLED_CONST.commandMode, this.displayHeight - 1);
      this.#registerQueue(OLED_CONST.commandMode, 0xd3);  // Set Display Offset
      this.#registerQueue(OLED_CONST.commandMode, 0x00);
      this.#registerQueue(OLED_CONST.commandMode, 0x40);  // Set Start Line
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.chargePumpSettingCmd); // 0x8d
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.chargePumpEnableCmd);  // 0x14
      this.#registerQueue(OLED_CONST.commandMode, 0x20);  // Set Memory Addressing Mode
      this.#registerQueue(OLED_CONST.commandMode, 0x02);  // Page mode
      this.#registerQueue(OLED_CONST.commandMode, 0xa0);  // Set Segment Re-map (SEG0→col0)
      this.#registerQueue(OLED_CONST.commandMode, 0xc0);  // Set COM Output Scan Direction (COM0→row0)
      this.#registerQueue(OLED_CONST.commandMode, 0xda);  // Set COM Pins Hardware Configuration
      this.#registerQueue(OLED_CONST.commandMode, comPins);
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.setBrightnessCmd);    // 0x81
      this.#registerQueue(OLED_CONST.commandMode, 0xcf);  // Contrast value
      this.#registerQueue(OLED_CONST.commandMode, 0xd9);  // Set Pre-charge Period
      this.#registerQueue(OLED_CONST.commandMode, 0xf1);
      this.#registerQueue(OLED_CONST.commandMode, 0xdb);  // Set VCOMH Deselect Level
      this.#registerQueue(OLED_CONST.commandMode, 0x40);
      this.#registerQueue(OLED_CONST.commandMode, 0xa4);  // Entire Display ON (resume from RAM)
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.normalDisplayCmd);    // 0xa6
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.displayOnCmd);        // 0xaf
      return;
    }
    if (this.useSSD1306) {
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.chargePumpSettingCmd);
      this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.chargePumpEnableCmd);
      if (this.displayHeight !== 64) {
        this.#registerQueue(OLED_CONST.commandMode, 0xa8);  // Set Multiplex Ratio
        this.#registerQueue(OLED_CONST.commandMode, this.displayHeight - 1);
        this.#registerQueue(OLED_CONST.commandMode, 0xda);  // Set COM Pins Hardware Configuration
        this.#registerQueue(OLED_CONST.commandMode, comPins);
      }
    }
    this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.displayOffCmd);
    this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.displayOnCmd);
    this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.normalDisplayCmd);
  }

  putCharQ(char) {
    let c = char.charCodeAt(0);
    if (c < 32 || c > 127) {
      c = 32;
    }
    let word = 0;
    for (let i = 0; i < 8; i++) {
      if (i % 2) {
        word |= OLED_CONST.basicFont[c - 32][i] << 8;
        this.#registerQueue(OLED_CONST.dataMode, word);
      } else {
        word = OLED_CONST.basicFont[c - 32][i];
      }
    }
  }

  putStringQ(string) {
    if (typeof string === "object") {
      console.warn(`Ignoring invalid parameter: "${string}" is not string.`);
      return;
    }
    if (typeof string === "number" || typeof string === "boolean") {
      string = `${string}`;
    }
    for (let i = 0; i < string.length; i++) {
      const c = string.charAt(i);
      this.putCharQ(c);
    }
  }

  drawStringQ(row, col, string) {
    this.setTextXYQ(row, col);
    this.putStringQ(string);
  }

  setBrightnessQ(Brightness) {
    this.#registerQueue(OLED_CONST.commandMode, OLED_CONST.setBrightnessCmd);
    this.#registerQueue(OLED_CONST.commandMode, Brightness);
  }

  setHorizontalModeQ() {
    this.addressingMode = OLED_CONST.horizontalMode;
    this.#registerQueue(OLED_CONST.commandMode, 0x20);
    this.#registerQueue(OLED_CONST.commandMode, 0);
  }

  setPageModeQ() {
    this.addressingMode = OLED_CONST.pageMode;
    this.#registerQueue(OLED_CONST.commandMode, 0x20);
    this.#registerQueue(OLED_CONST.commandMode, 0x02);
  }

  setTextXYQ(row, col) {
    const colAddr = this.columnOffset + (8 * col);
    this.#registerQueue(OLED_CONST.commandMode, 0xb0 + row);
    this.#registerQueue(OLED_CONST.commandMode, 0x00 + (colAddr & 0x0f));
    this.#registerQueue(OLED_CONST.commandMode, 0x10 + ((colAddr >> 4) & 0x0f));
  }

  clearLineQ(row) {
    const wordsPerLine = this.displayWidth / 2;
    this.setTextXYQ(row, 0);
    for (let i = 0; i < wordsPerLine; i++) {
      this.#registerQueue(OLED_CONST.dataMode, 0x0000);
    }
  }

  clearDisplayQ() {
    const pages = this.displayHeight / 8;
    const totalWords = (this.displayWidth * pages) / 2;
    // 水平アドレッシングモードに切り替え（ページ切替コマンドなしで全画面連続書き込み）
    this.#registerQueue(OLED_CONST.commandMode, 0x20);
    this.#registerQueue(OLED_CONST.commandMode, 0x00);
    // カラムアドレス範囲: columnOffset 〜 columnOffset+displayWidth-1
    this.#registerQueue(OLED_CONST.commandMode, 0x21);
    this.#registerQueue(OLED_CONST.commandMode, this.columnOffset);
    this.#registerQueue(OLED_CONST.commandMode, this.columnOffset + this.displayWidth - 1);
    // ページアドレス範囲: 0 〜 pages-1
    this.#registerQueue(OLED_CONST.commandMode, 0x22);
    this.#registerQueue(OLED_CONST.commandMode, 0x00);
    this.#registerQueue(OLED_CONST.commandMode, pages - 1);
    // 全ピクセルを 0x00 で塗りつぶし
    for (let i = 0; i < totalWords; i++) {
      this.#registerQueue(OLED_CONST.dataMode, 0x0000);
    }
    // ページモードに戻す
    this.addressingMode = OLED_CONST.pageMode;
    this.#registerQueue(OLED_CONST.commandMode, 0x20);
    this.#registerQueue(OLED_CONST.commandMode, 0x02);
  }

  #registerQueue(mode, param) {
    if (this.sequence != null) {
      console.error("OledDisplay.#registerQueue(): error! (now playing)");
      return;
    }
    const obj = { mode: mode, param: param };
    this.funcQueue.push(obj);
  }

  async init(deviceTypeOrOptions, width, height, columnOffset, comPins) {
    if (deviceTypeOrOptions !== null && typeof deviceTypeOrOptions === 'object') {
      // Object form: init({ device, width, height, offset, isAlternate })
      const { device, width: w, height: h, offset, isAlternate } = deviceTypeOrOptions;
      if (device === "SSD1306") {
        this.useSSD1306 = true;
      } else if (device === "SSD1315") {
        this.useSSD1315 = true;
      }
      if (w) this.displayWidth = w;
      if (h) this.displayHeight = h;
      if (offset !== undefined) this.columnOffset = offset;
      if (isAlternate === true) this.comPins = 0x12;
      // isAlternate false/undefined → comPins stays null (auto / height-based)
    } else if (deviceTypeOrOptions === true) {
      // backward compat: init(true) → SSD1306, 128x64
      this.useSSD1306 = true;
    } else {
      // Positional form: init(device?, width?, height?, columnOffset?, comPins?)
      if (deviceTypeOrOptions === "SSD1306") {
        this.useSSD1306 = true;
      } else if (deviceTypeOrOptions === "SSD1315") {
        this.useSSD1315 = true;
      }
      // else: default SSD1308 (useSSD1306/useSSD1315 both false)
      if (width) this.displayWidth = width;
      if (height) this.displayHeight = height;
      if (columnOffset !== undefined) this.columnOffset = columnOffset;
      if (comPins === true) this.comPins = 0x12;
      // comPins false/undefined → comPins stays null (auto / height-based)
    }
    this.i2cSlave = await this.i2cPort.open(this.slaveAddress);
    this.#initQ();
    await this.playSequence();
  }

  async playSequence() {
    if (this.i2cSlave == null) {
      throw new Error("i2cSlave Address does'nt yet open!");
    }
    if (this.sequence != null) {
      console.error("OledDisplay.playSequence(): error! (multiple call)");
      throw new Error("playSequence already running");
    }
    this.sequence = true;
    const MAX_WRITE_BYTES = 128;
    try {
      let i = 0;
      while (i < this.funcQueue.length) {
        const item = this.funcQueue[i];
        if (item.mode === OLED_CONST.commandMode) {
          await this.i2cSlave.write8(OLED_CONST.commandMode, item.param);
          i++;
        } else {
          // 連続するデータエントリを最大128バイトずつ writeBytes でまとめて送信
          const buf = [];
          while (i < this.funcQueue.length &&
                 this.funcQueue[i].mode === OLED_CONST.dataMode &&
                 buf.length + 2 <= MAX_WRITE_BYTES) {
            const word = this.funcQueue[i].param;
            buf.push(word & 0xff);
            buf.push((word >> 8) & 0xff);
            i++;
          }
          await this.i2cSlave.writeBytes(new Uint8Array([OLED_CONST.dataMode, ...buf]));
        }
      }
    } finally {
      this.sequence = null;
      this.funcQueue = [];
    }
  }

  async clearDisplay() {
    if (this.i2cSlave == null) {
      throw new Error("i2cSlave Address does'nt yet open!");
    }
    this.clearDisplayQ();
    await this.playSequence();
  }

  async drawString(row, col, string) {
    if (this.i2cSlave == null) {
      throw new Error("i2cSlave Address does'nt yet open!");
    }
    this.drawStringQ(row, col, string);
    await this.playSequence();
  }
}

export default OledDisplay;
